/* Wide string (WCHAR = uint16_t) length + encode/decode               */
/* ------------------------------------------------------------------ */

/* Platform-safe WCHAR string length.  WCHAR is always uint16_t (2 bytes)
 * on the wire, but wchar_t may be 4 bytes on Linux.  Scan uint16_t
 * elements directly to get the correct count. */
static inline size_t npt_wcslen(const WCHAR *s)
{
    size_t n = 0;
    while (s[n])
        n++;
    return n;
}

static inline void npt_decode_wchar_array(struct npt_cs_decoder *dec,
                                          WCHAR *val, size_t byte_size)
{
    npt_decode_blob_array(dec, val, byte_size);
    if (byte_size >= sizeof(WCHAR))
        val[byte_size / sizeof(WCHAR) - 1] = 0;
    else if (byte_size)
        npt_cs_decoder_set_fatal(dec);
}

