/* void * (opaque pointer) encode/decode                               */
/* ------------------------------------------------------------------ */

/* The codegen emits npt_sizeof_void / npt_encode_void / npt_decode_void
 * for void ** output parameters (e.g. ID3D11VideoContext::GetDecoderBuffer's
 * ppBuffer, ID3D12Resource::Map's ppData).  On the wire a void* is
 * represented as a uint64 host-pointer-as-id. */

static inline size_t npt_sizeof_void(const void *val, int max_mode)
{
    return sizeof(uint64_t);
}

static inline void npt_encode_void(struct npt_cs_encoder *enc,
                                   const void *val)
{
    uint64_t id = (uint64_t)(uintptr_t)(*(const void *const *)val);
    npt_encode_uint64_t(enc, &id);
}

static inline void npt_decode_void(struct npt_cs_decoder *dec, void *val)
{
    uint64_t id;
    npt_decode_uint64_t(dec, &id);
    *(void **)val = (void *)(uintptr_t)id;
}

